interface Item {
  type: string;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Customer {
  yearsWithMHPCO: number;
}

interface Scenario {
  customer: Customer;
  steps: QuoteStep[];
}

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
};

const PROCESSING_FEE = 5;

const quotePremium = (step: QuoteStep): number => {
  let total = 0;
  for (const item of step.items) {
    const base = BASE_PREMIUM[item.type];
    total += base * 1.1; // 10% first-insurance surcharge per item
  }
  return Math.ceil(total) + PROCESSING_FEE;
};

export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
  const results = scenario.steps.map((step) => ({ premium: quotePremium(step) }));
  return { results };
};

