const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;

const itemPremium = (item: Item): number => {
  const base = BASE_PREMIUM[item.type];
  return base + base * FIRST_INSURANCE_SURCHARGE_RATE;
};

const quotePremium = (step: QuoteStep): number => {
  const total = step.items.reduce((sum, item) => sum + itemPremium(item), 0);
  return Math.ceil(total) + PROCESSING_FEE;
};

export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
  const results = scenario.steps.map((step) => ({ premium: quotePremium(step) }));
  return { results };
};

