interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Customer {
  yearsWithMHPCO: number;
}

interface Scenario {
  customer: Customer;
  steps: QuoteStep[];
}

const MAIN_ITEM_BASE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const COMPONENT_BASE = 25;
const BLOCK_SIZE = 3;
const BLOCK_BASE = 60;

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
const CURSED_SURCHARGE_RATE = 0.5;

const componentGroupBase = (count: number): number => {
  if (count === BLOCK_SIZE) return BLOCK_BASE;
  return count * COMPONENT_BASE;
};

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const sumMainItems = (items: Item[]): number =>
  items
    .filter((item) => !isComponent(item))
    .reduce((total, item) => total + MAIN_ITEM_BASE[item.type], 0);

const countByType = (items: Item[]): Record<string, number> => {
  const counts: Record<string, number> = {};
  for (const item of items) {
    counts[item.type] = (counts[item.type] ?? 0) + 1;
  }
  return counts;
};

const sumComponentGroups = (items: Item[]): number => {
  const counts = countByType(items.filter(isComponent));
  return Object.values(counts).reduce((total, count) => total + componentGroupBase(count), 0);
};

const policyBasePremium = (items: Item[]): number =>
  sumMainItems(items) + sumComponentGroups(items);

const quotePremium = (step: QuoteStep): number => {
  const base = policyBasePremium(step.items);
  const withFirstInsurance = base + base * FIRST_INSURANCE_SURCHARGE_RATE;
  return Math.ceil(withFirstInsurance) + PROCESSING_FEE;
};

export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
  const results = scenario.steps.map((step) => ({ premium: quotePremium(step) }));
  return { results };
};

