import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // ---- Edge case: empty policy ----
  it("empty item list → premium 5 G (only the processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });

  // ---- Base premiums for single main items (+ fee) ----
  it("single sword, newcomer → premium 115 G (100 base + 10 first-insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("single amulet, newcomer → premium 71 G (60 base + 6 first-insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("single staff, newcomer → premium 93 G (80 base + 8 first-insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "staff" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 93 }] });
  });
  it("single potion, newcomer → premium 49 G (40 base + 4 first-insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "potion" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 49 }] });
  });

  // ---- Components and building blocks ----
  it("2 runes, newcomer → premium 60 G (50 base + 5 first-insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 60 }] });
  });
  it("3 runes (block), newcomer → premium 71 G (60 block base + 6 first-insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("4 runes (no block), newcomer → premium 115 G (100 base + 10 first-insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("7 runes (no block), newcomer → premium 198 G (175 base + 17.5 first-insurance → ceil 193 + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: Array.from({ length: 7 }, () => ({ type: "rune" })) }],
    });
    expect(result).toEqual({ results: [{ premium: 198 }] });
  });

  // ---- "Alike" components ----
  it("2 runes + 1 moonstone (no block, different types), newcomer → premium 88 G (75 base + 7.5 first-insurance → ceil 83 + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 88 }] });
  });
  it("3 runes + 3 moonstones (two blocks), newcomer → premium 137 G (120 base + 12 first-insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "moonstone" },
            { type: "moonstone" },
            { type: "moonstone" },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 137 }] });
  });

  // ---- Item-specific modifiers in isolation ----
  it("cursed sword (steel, ench 3), newcomer → premium 165 G (100 base + 50 curse + 10 first-insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 165 }] });
  });
  it("sword enchantment exactly 5 (high-ench surcharge), newcomer → premium 145 G (100 base + 30 high-ench + 10 first-insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 145 }] });
  });
  it("sword enchantment 4 (no high-ench surcharge), newcomer → premium 115 G (100 base + 10 first-insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 4, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });

  // ---- Modifier scope on multi-item policies ----
  it("cursed sword + plain amulet, newcomer → premium 231 G (160 base + 50 curse(sword) + 16 first-insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "sword", material: "steel", enchantment: 3, cursed: true },
            { type: "amulet", material: "silver", enchantment: 1, cursed: false },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 231 }] });
  });

  // ---- Policy-wide modifiers ----
  it("customer exactly 2 years, single sword → premium 95 G (100 base + 10 first-insurance - 20 loyalty + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 2 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 95 }] });
  });
  it.todo("first insurance → 10% initial assessment surcharge");
  it.todo("follow-up contract (2nd quote) → 15% discount on the contract");

  // ---- Rounding ----
  it.todo("premium calc yielding 197.5 G → final premium 198 G (rounded up)");
  it.todo("payout calc yielding 350.5 G → final payout 350 G (rounded down)");

  // ---- Claim: standard reimbursement ----
  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G (full − 100 deductible)");
  it.todo("rune (value 250 G), damage 200 G → payout 100 G (full − 100 deductible)");

  // ---- Claim: special clauses ----
  it.todo("dragon-material sword, ench 8, damage 1000 G → payout 400 G (50% then deductible)");
  it.todo("dragon-material sword, ench 9, damage 1000 G → payout 400 G (both clauses, 50% wins)");
  it.todo("dragon-material sword, ench 5, damage 800 G → payout 700 G (dragon only: full then deductible)");
  it.todo("steel sword, ench 9, damage 1000 G → payout 400 G (high-ench only: 50% then deductible)");

  // ---- Claim: deductible per damage event ----
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible once per item)");

  // ---- Claim: multiple items of the same type ----
  it.todo("policy with two swords → insurance sum 2000 G, cap 4000 G");
  it.todo("two sword damages, two swords insured → each is a separate damage with own deductible");
  it.todo("more damages of a type than insured (2 sword damages, 1 sword) → CLI exits non-zero, claim rejected");

  // ---- Cap and insurance sum ----
  it.todo("sword + amulet → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword → cap 2000 G (based on unmodified insurance value)");
  it.todo("sword + 3 runes (block) → insurance sum 1750 G (block discount affects premium only)");
  it.todo("sword (cap 2000), two claims of 1500 each → 1400 then 600; cap remaining 600 then 0");

  // ---- Edge cases (errors) ----
  it.todo("quote with unknown item type (broomstick) → CLI exits non-zero, error to stderr, no results");
  it.todo("claim references item not in policy (amulet when only sword insured) → CLI exits non-zero, error to stderr");
  it.todo("claim with negative amount (-200) → CLI exits non-zero, error to stderr");

  // ---- Integration examples ----
  it.todo("newcomer with cursed sword (steel, ench 3) → premium 165 G");
  it.todo("long-standing customer (3y) second contract, cursed sword (steel, ench 7) → premium 160 G");
});

